  ('fire-eq-eng-moex-01112', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防法規定，下列裁處之案件，何者不須經限期改善之程序，應逕行舉發並裁處？', '["違反第9條有關檢修設備之規定", "違反第6條第1項消防安全設備設置、維護之規定", "違反第11條第2項銷售非附有防焰標示之防焰物品或其材料", "違反第13條規定，未依法遴用防火管理人"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "d2e9dde1663a", "answer_pdf_sha1": "3cb24e4147ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL)
